// Event types
type DepositedEvent = {
  type: 'Deposited';
  amount: number;
  timestamp: Date;
};

type WithdrawnEvent = {
  type: 'Withdrawn';
  amount: number;
  timestamp: Date;
};

type TransferredOutEvent = {
  type: 'TransferredOut';
  amount: number;
  toAccountId: string;
  timestamp: Date;
};

type TransferredInEvent = {
  type: 'TransferredIn';
  amount: number;
  fromAccountId: string;
  timestamp: Date;
};

type AccountEvent = DepositedEvent | WithdrawnEvent | TransferredOutEvent | TransferredInEvent;

// Custom errors


class InsufficientFundsError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'InsufficientFundsError';
  }
}

class InvalidAmountError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'InvalidAmountError';
  }
}

// Account aggregate
class Account {
  private balance: number = 0;
  private events: AccountEvent[] = [];
  private accountId: string;

  constructor(accountId: string) {
    this.accountId = accountId;
  }

  deposit(amount: number): void {
    if (amount <= 0) throw new InvalidAmountError('Deposit amount must be positive'); this.events.push({ type: 'Deposited', amount, timestamp: new Date() }); this.balance += amount;
  }

  withdraw(amount: number): void {
    if (amount <= 0) throw new InvalidAmountError('Withdrawal amount must be positive'); if (this.balance < amount) throw new InsufficientFundsError('Insufficient funds'); this.events.push({ type: 'Withdrawn', amount, timestamp: new Date() }); this.balance -= amount;
  }

  transfer(amount: number, toAccountId: string): void {
    if (amount <= 0) throw new InvalidAmountError('Transfer amount must be positive'); if (this.balance < amount) throw new InsufficientFundsError('Insufficient funds'); this.events.push({ type: 'TransferredOut', amount, toAccountId, timestamp: new Date() }); this.balance -= amount;
  }

  receiveTransfer(amount: number, fromAccountId: string): void {
    this.events.push({ type: 'TransferredIn', amount, fromAccountId, timestamp: new Date() }); this.balance += amount;
  }

  getBalance(): number {
    return this.balance;
  }

  getEvents(): AccountEvent[] {
    return [...this.events];
  }

  static fromEvents(accountId: string, events: AccountEvent[]): Account {
    const account = new Account(accountId); events.forEach(event => { if (event.type === 'Deposited') account.balance += event.amount; else if (event.type === 'Withdrawn') account.balance -= event.amount; else if (event.type === 'TransferredOut') account.balance -= event.amount; else if (event.type === 'TransferredIn') account.balance += event.amount; }); account.events = [...events]; return account;
  }
}

export { Account, AccountEvent, DepositedEvent, WithdrawnEvent, TransferredOutEvent, TransferredInEvent, InsufficientFundsError, InvalidAmountError };
```

The deposit method validates positive amounts and records the event while updating the balance. Withdrawal and transfer operations check both amount validity and sufficient funds before applying changes. The receiveTransfer method handles incoming transfers without validation since the sending account already verified funds. Event sourcing is maintained through the fromEvents static method, which reconstructs account state by replaying all historical events.

